1	export type Item = {
2	  type: string;
3	};
4	
5	export type QuoteStep = {
6	  op: "quote";
7	  items: Item[];
8	};
9	
10	export type Step = QuoteStep;
11	
12	export type Scenario = {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	};
16	
17	export type QuoteResult = { premium: number };
18	export type StepResult = QuoteResult;
19	export type ScenarioResult = { results: StepResult[] };
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	};
31	
32	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
33	
34	const sumItemBasePremiums = (items: Item[]): number =>
35	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
36	
37	const quoteStep = (step: QuoteStep): QuoteResult => {
38	  const baseTotal = sumItemBasePremiums(step.items);
39	  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
40	  const premium = Math.ceil(baseTotal + firstInsuranceSurcharge + PROCESSING_FEE);
41	  return { premium };
42	};
43	
44	export const runScenario = (scenario: Scenario): ScenarioResult => ({
45	  results: scenario.steps.map(quoteStep),
46	});
